#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vUv = mix(vUvOriginal,vUv,0);
vec2 ac = vec2(q11,q12);
vec2 mu = vec2(q13,q14);
vec2 c = vec2(q15,q16);
vec2 d = vec2(q17,q18);

vec2 z = (vUv-0.5);

// (c*z + d)
vec2 czd = vec2(z.x*c.x-z.y*c.y,z.x*c.y-z.y*c.x)*uAspect.yx + d;
// mu/(cz+d)
vec2 moebius = vec2( mu.x*czd.x + mu.y*czd.y , mu.y*czd.x-mu.x*czd.y )/(czd.x*czd.x+czd.y*czd.y) + ac;

//moebius = 0.5 + (1.0 - abs( fract( moebius * 0.5 ) * 2 - 1.0 )-0.5);


ret.x = texture( sampler_fc_main, fract(moebius) ).x*0.96 - 0.004;

ret.yz = GetPixel(vUv).yz*0.96 - 0.004;
//ret = mix(ret, GetPixel(vUvOriginal), 0.5); // motion-blur comes so cool with this one...


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = 0.5 + (vUv-0.5)*0.95;
vec2 uvo = vUv;
vUv = (vUv-0.5);
factorA = vUv+ vec2(q1,q2);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv1 = product;
factorA = vUv+ vec2(q3,q4);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv2 = product;
factorA = vUv+ vec2(q5,q6);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv3 = product;
factorA = vUv+ vec2(q7,q8);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv4 = product;
factorA = uv1;
factorB = uv2;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv12 = product;
factorA = uv3;
factorB = uv4;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv34 = product;
factorA = uv12;
factorB = uv34;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
numerator = vec2(1,0);
denominator = product;
fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction.yx*vec2(-1,1)*32;
vUv = mix(0.5 + (uvo-0.5)*2,vUv+0.5,0.5);
float l = length(vUv-0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5); // Eo.S. mirror code with cutted borders
ret = mix(vec3(0.8,0.5,0),-0.5,(GetBlur2(vUv)*2-GetPixel(vUv)).x);
ret = mix(ret,1,(GetBlur3(vUv)*2-GetPixel(vUv)).y*1.5);
float c =clamp01(1.6-pow(l,6)*0.004);
ret = mix((GetBlur3(uvo)*2-GetPixel(uvo)).y,ret,c);

  fragColor = ret;
}
